async function ask(prompt: string): Promise<string> {
  try {
    const res = await callModel(prompt)   // waits for the Promise
    return res.text
  } catch (err) {
    console.error("model failed", err)
    throw err
  }
}

// Sequential: each await waits for the previous (slow)
const a = await embed(chunks[0])
const b = await embed(chunks[1])

// Parallel: start together, then await all (fast)
const [x, y] = await Promise.all([embed(chunks[0]), embed(chunks[1])])

function timeout(ms: number): Promise<never> {
  return new Promise((_, reject) =>
    setTimeout(() => reject(new Error("timeout")), ms),
  )
}

const res = await Promise.race([callModel(prompt), timeout(10_000)])

const results = await Promise.allSettled(prompts.map(callModel))
for (const r of results) {
  if (r.status === "fulfilled") use(r.value)
  else console.warn("failed:", r.reason)
}
